  ('dietitian-moex-11016', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '廚房的工作區可分為清潔區和污染區，今有一餐盒食品工廠的包裝區，應屬於下列何區才對？ 清潔區    介於清潔區與準清潔區之間 準清潔區    污染區', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "26283d62182b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11017', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '何種食品添加物已禁用？ 過氧化氫  亞硝酸鈉  硼砂  安息香酸鈉', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "26283d62182b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
